    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components == 1) {
        long long min_s = LLONG_MAX;
        for (const auto& e : must_edges) {
            min_s = min(min_s, e[2]);
        }
        return min_s;
    }

    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    vector<vector<long long>> upgraded_edges;
    for (const auto& e : optional_edges) {
        upgraded_edges.push_back({e[0], e[1], e[2] * 2, e[3]});
    }

    auto kruskal = [&](vector<vector<long long>>& edges, long long k) -> pair<long long, long long> {
        DSU temp_dsu(n);
        long long used_k = 0;
        long long min_s = LLONG_MAX;
        for (const auto& e : must_edges) {
            temp_dsu.unite(e[0], e[1]);
        }

        for (auto& e : edges) {
            if (temp_dsu.unite(e[0], e[1])) {
                if (e[3] == 0 && used_k < k) {
                    min_s = min(min_s, e[2]);
                    used_k++;
                } else {
                    min_s = min(min_s, e[2]);
                }
            }
        }
        int root = temp_dsu.find(0);
        for (int i = 1; i < n; ++i) {
            if (temp_dsu.find(i) != root) {
                return {-1, -1};
            }
        }
        return {min_s, used_k};
    };

    long long left = 0;
    long long right = 1e18;
    long long answer = -1;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        vector<vector<long long>> filtered_edges;
        for (const auto& e : optional_edges) {
            if (e[2] >= mid) {
                filtered_edges.push_back(e);
            } else if (e[2] * 2 >= mid) {
                filtered_edges.push_back({e[0], e[1], e[2] * 2, e[3]});
            }
