            if (a[3] == b[3]) {
                return a[2] > b[2];
            }
            return a[3] > b[3];
        });

        DSU check_dsu(n);
        int comp = n;
        long long used_k = 0;
        bool possible = true;
        for (const auto& e : must_edges) {
            if (check_dsu.unite(e[0], e[1])) {
                comp--;
            }
        }

        for (const auto& e : filtered_edges) {
