        } else if (rank[pu] < rank[pv]) {
            parent[pu] = pv
        } else {
            parent[pv] = pu
            rank[pu]++
        }
        return true
    }
}

fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val mustEdges = mutableListOf<Array<Long>>()
    val optionalEdges = mutableListOf<Array<Long>>()
    for (e in edges) {
        if (e[3] == 1L) {
            mustEdges.add(e)
        } else {
            optionalEdges.add(e)
        }
    }

