    var components = n.toInt()
    for (e in mustEdges) {
        if (dsu.unite(e[0].toInt(), e[1].toInt())) {
            components--
        }
    }

    if (components == 1) {
        var minS = Long.MAX_VALUE
        for (e in mustEdges) {
            minS = minOf(minS, e[2])
        }
        return minS
    }

    optionalEdges.sortWith(compareByDescending { it[2] })

    var left = 0L
    var right = 1e18.toLong()
    var answer = -1L

    while (left <= right) {
        val mid = left + (right - left) / 2
        val filteredEdges = mutableListOf<Array<Long>>()
        for (e in optionalEdges) {
            if (e[2] >= mid) {
                filteredEdges.add(e.copyOf())
            } else if (e[2] * 2 >= mid) {
                filteredEdges.add(arrayOf(e[0], e[1], e[2] * 2, e[3]))
            }
        }
        filteredEdges.sortWith(compareBy<Array<Long>> { -it[3] }.thenByDescending { it[2] })

        val checkDsu = DSU(n.toInt())
        var comp = n.toInt()
        var usedK = 0L
