                    comp--
                    if (e[3] == 0L) {
                        if (e[2] == 2 * (e[2] / 2) && e[2] != e[2] / 2) {
                            usedK++
                        }
                    }
                }
            }
        }

        if (comp == 1 && usedK <= k) {
            answer = mid
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return answer
}
